script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, null, 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;&VoucherLogHandleStatus;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  f.setReferenceKeyFilter('ma_dc');
  onChange$Voucher$Shipto(f.getItem('ma_dc'));

      &APVSetReadOnlyFields;
      &APVHandleStatus;
      &ListCreate;
      &PostCreate;
}
function scatter$Voucher$(f) {
      &ScriptScatterVoucher;
      &APVSetReadOnlyFields;
      &VoucherLogHandleStatus;
  f.setReferenceKeyFilter('ma_dc');
  onChange$Voucher$Shipto(f.getItem('ma_dc'));
}
function close$Voucher$(f) {&ScriptCloseVoucher;
  &ListDispose;
  &PostDispose;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d94')._controlBehavior;
  switch (action) {
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Check':
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &APVAddStatus;
      &VoucherLogHandleStatusExplore;

      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
   create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d94')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt,t_thue_nt,t_tt_nt : t_tien,t_thue,t_tt');
    v.addGridFields(g, 'gia_nt,tien_nt,thue_nt:gia,tien,thue');
    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_tien', 'tien'], ['t_thue_nt', 'thue_nt'], ['t_thue', 'thue']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tt_nt]:=[t_tien_nt] + [t_thue_nt]', '[t_tt]:=[t_tien] + [t_thue]']);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type){
      e.object._form.focusWhenTabChanged([['d94', 'ma_thue'], 'ma_dc', 'nha_cung_cap'&ListTabChange;&PostTabChange;, 'ma_nv']);
      &PostCurrencySelected;
    }
  }
}


function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d94', 'ma_dc', 'nha_cung_cap'&ListTabChange;&PostTabChange;, 'ma_nv']);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$CreateDate(o) {o.parentForm.getItem('ngay_ct').value = o.parentForm.getItem('ngay_lct').value;}
function onChange$Voucher$TransactionCode(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$Shipto(o) {o.parentForm.request('Shipto', 'Shipto', ['ma_dc'], o);}
/* </flatten> */

function on$Voucher$ResponseComplete(sender, e) {
var f = e.object, context = e.type.Context, result = e.type.Result, g = f.getItem('d94')._controlBehavior;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      &APVSetVoucherDefaultValue;
      set$Voucher$DefaultValue(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &APVSetVoucherDefaultValue;
      set$Voucher$DefaultValue(f);
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    case 'Customer':
      f.setItemControlBehavior('ma_tt', result[0].Value, result[1].Value, false);
      f.setItemControlBehavior('nha_cung_cap', result[2].Value, null, false);
      f.setItemControlBehavior('dia_chi', result[3].Value, null, false);
      f.setItemControlBehavior('dien_thoai', result[4].Value, null, false);
      f.setItemControlBehavior('fax', result[5].Value, null, false);
      break;
    case 'Shipto':
      f.setItemValue('ma_kho0', result[0].Value);
      f.setItemValue('ten_kho', result[1].Value);
      break;
    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      set$Voucher$DependOnVoucherType(f);
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$DefaultValue(f) {
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  if (f._action != 'View') set$Voucher$DependOnVoucherType(f);
}

function set$Voucher$DependOnVoucherType(f) {
  var o = f.getItem('ngay_ct3'), t = $func.trim(f.getItemValue('loai_ct')), v = (t == '2');
  o.disabled = !v;
  $common.setVisible(o.a, v);
}
/* </flatten> */
function when$VoucherCopying(f) {&APVWhenVoucherCopying;}

      &APVFunctionScript;
      &ListScript;
      &PostScript;

dir.response:
&CommandSetVoucherNumber;
if exists(select 1 from dmkh where ma_kh = @ma_kh) begin select rtrim(a.ma_tt) as ma_tt, b.ten_tt%l, rtrim(a.ten_kh%l) as nha_cung_cap, rtrim(a.dia_chi) as dia_chi, rtrim(a.dien_thoai) as dien_thoai, rtrim(a.fax) as fax from dmkh a left join dmtt b on a.ma_tt = b.ma_tt where a.ma_kh = @ma_kh return end
select loai_ct from dmmagd where ma_ct = 'PO1' and ma_gd = @ma_gd return
if exists(select 1 from dmdc where ma_dc = @ma_dc) begin declare @c varchar(32) select @c = ma_kho from dmdc where ma_dc = @ma_dc if dbo.FastBusiness$Function$CheckSiteRights('PO1', '', @c, @@userID, @@admin) = 0 select '' as ma_kho, '' as ten_kho else select a.ma_kho, case when @@language = 'v' then b.ten_kho else b.ten_kho2 end as ten_kho from dmdc a left join dmkho b on a.ma_kho = b.ma_kho where ma_dc = @ma_dc return end else begin select '' as ma_kho, '' as ten_kho return end
&XMLGetVoucherNumber; &XMLGetExchangeRate; &ListTicket;
